import requests

papers = [
    ('https://arxiv.org/pdf/2502.12289', 'papers/2502.12289_survey_evaluating_reasoning_traces.pdf'),
    ('https://arxiv.org/pdf/2103.07191', 'papers/2103.07191_patel2021_svamp.pdf'),
    ('https://arxiv.org/pdf/2109.01652', 'papers/2109.01652_ho2022_large_language_models_trained.pdf'),
]

# Also try SSRN paper (might not work)
for url, path in papers:
    try:
        resp = requests.get(url, timeout=60, headers={'User-Agent': 'Mozilla/5.0'})
        if resp.status_code == 200 and len(resp.content) > 10000:
            with open(path, 'wb') as f:
                f.write(resp.content)
            print(f'Downloaded {path} ({len(resp.content)} bytes)')
        else:
            print(f'Failed {url}: status={resp.status_code}, size={len(resp.content)}')
    except Exception as e:
        print(f'Error {url}: {e}')
"
